"use client"

import { FormEvent, useState } from 'react'
import { useRouter } from 'next/navigation'

export default function AdminLoginPage() {
  const router = useRouter()
  const [username, setUsername] = useState('')
  const [password, setPassword] = useState('')
  const [error, setError] = useState('')
  const [loading, setLoading] = useState(false)

  async function onSubmit(e: FormEvent) {
    e.preventDefault()
    setLoading(true)
    setError('')
    try {
      const res = await fetch('/api/admin/auth/login', {
        method: 'POST',
        credentials: 'include',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password }),
      })
      const data = await res.json()
      if (!res.ok) {
        setError(data.error || '登录失败')
        return
      }
      router.push('/dashboard')
      router.refresh()
    } catch {
      setError('网络错误，请稍后重试')
    } finally {
      setLoading(false)
    }
  }

  return (
    <div style={{maxWidth: 420, margin: '80px auto', background: 'white', padding: 24, borderRadius: 12, boxShadow: '0 2px 10px rgba(0,0,0,.05)'}}>
      <h2 style={{marginTop:0}}>管理员登录</h2>
      <p style={{color:'#6b7280'}}>使用 root 账号登录 InkSight 管理后台。</p>
      <form onSubmit={onSubmit} style={{display:'grid', gap: 12}}>
        <input value={username} onChange={(e)=>setUsername(e.target.value)} placeholder="用户名" style={{padding:'12px', border:'1px solid #d1d5db', borderRadius:8}} />
        <input type="password" value={password} onChange={(e)=>setPassword(e.target.value)} placeholder="密码" style={{padding:'12px', border:'1px solid #d1d5db', borderRadius:8}} />
        {error ? <div style={{color:'#b91c1c', fontSize:14}}>{error}</div> : null}
        <button disabled={loading} style={{padding:'12px', border:0, borderRadius:8, background:'#111827', color:'white', cursor:'pointer'}}>{loading ? '登录中…' : '登录'}</button>
      </form>
    </div>
  )
}
